        "question_text": "Provide details on your climate risk and vulnerability assessment.",
        "row_order": 3,
        "row_name": "Row 3",
        "Assessment attachment^": "新北市地區災害防救計畫.pdf",
        "Assessment direct link^": "https://www.fire.ntpc.gov.tw/ebook/w0920/index.html",
